// 1. Pega o array de mapeamento da propriedade 'data' do primeiro item de entrada.
// Assumimos que o nó Merge entregou um único item contendo a estrutura mostrada.
const mapping = items[0].json.data;

// 2. Cria um lookup rápido por ID (string) a partir do array de mapeamento
const lookup = mapping.reduce((acc, cur) => {
  // Garante que o ID é tratado como string para a comparação
  acc[cur.id.toString()] = cur.name_normalize;
  return acc;
}, {});

// 3. Prefixo que identifica os campos a renomear
const prefix = "actions_offsite_conversion.custom.";

// 4. Processa cada item de entrada (agora com dados mesclados)
const newItems = items.map(item => {
  // Faz uma cópia do JSON para não alterar o original
  const metrics = { ...item.json };

  // Remove a propriedade 'data' que contém o mapeamento, se não for mais necessária no output final
  // Verifique se 'data' existe antes de tentar deletar
  if (metrics.data !== undefined) {
      delete metrics.data;
  }

  const dynamicColumns = [];
  const dynamicValues = [];
  const dynamicUpdateSetParts = [];

  // Cria uma lista das chaves a serem removidas APÓS a iteração
  const keysToDelete = [];

  // Itera sobre todas as chaves no JSON de entrada
  Object.keys(metrics).forEach(key => {
    if (key.startsWith(prefix)) {
      const id = key.slice(prefix.length);          // extrai "1550197225663407"
      const normalizedName = lookup[id];            // encontra "FGTS_Contact", por ex.
      const columnValue = metrics[key]==0?1:metrics[key];             // O valor da coluna

      if (normalizedName) {
        // Construa a nova chave com o prefixo e o nome normalizado
        const newKey = prefix + normalizedName;

        // Adiciona à lista de colunas (usando o nome normalizado para o SQL)
        dynamicColumns.push(`\`${normalizedName}\``);

        // Adiciona à lista de valores (tratando nulos para SQL)
        dynamicValues.push(columnValue == null ? 'NULL' : columnValue);

        // Adiciona à lista de partes do ON DUPLICATE KEY UPDATE (usando o nome normalizado para o SQL)
        dynamicUpdateSetParts.push(`\`${normalizedName}\`=${columnValue == null ? 'NULL' : columnValue}`);

        // Adiciona o novo campo com a chave formatada corretamente ao objeto metrics
        metrics[newKey] = columnValue;

        // Marca a chave original para ser deletada após o loop
        keysToDelete.push(key);
      } else {
          // Opcional: Se um ID não for encontrado no mapeamento, você pode querer mantê-lo
          // ou tratá-lo de alguma forma. Por enquanto, ele será mantido no JSON
          // e não será incluído nas strings dinâmicas.
      }
    }
  });

  // Remove as chaves originais que foram processadas
  keysToDelete.forEach(key => {
      delete metrics[key];
  });


  // Junta as partes em strings separadas por vírgula
  const dynamicColumnsString = dynamicColumns.join(', ');
  const dynamicValuesString = dynamicValues.join(', ');
  const dynamicUpdateSetString = dynamicUpdateSetParts.join(', ');

  // Adiciona as strings geradas DIRETAMENTE AO OBJETO metrics
  // Elas estarão disponíveis para o próximo nó (MySQL)
  metrics.dynamicColumns = dynamicColumnsString;
  metrics.dynamicValues = dynamicValuesString;
  metrics.dynamicUpdateSet = dynamicUpdateSetString;

  // Retorna o item com o objeto metrics modificado
  return { json: metrics };
});

// 5. Retorna os itens processados
return newItems;

