// Campos numéricos para soma/agregação
const numericFields = [
  'spend', 'impressions', 'clicks_all', 'reach', 'unique_clicks', 'link_click', 'landing_page_view',
  'page_engagement', 'post_engagement', 'post_save', 'post_share', 'post_reaction', 'post_comment', 'post', 'post_like',
  'messaging_total', 'messaging_conversation_started_7d', 'messaging_block', 'messaging_first_reply',
  'messaging_2_message_send', 'messaging_3_message_send', 'messaging_5_message_send', 'contact',
  'initiate_checkout', 'initiate_checkout_value', 'lead', 'purchase', 'purchase_value', 'add_to_cart',
  'add_to_cart_value', 'complete_registration', 'view_content', 'subscriptions', 'schedule',
  'video_avg_time_watched', 'video_p25_watched', 'video_p50_watched', 'video_p75_watched',
  'video_p95_watched', 'video_p100_watched', 'video_play', 'video_view', 'clicks',
  // métricas adicionais de vídeo (agora calculadas como número absoluto)
  'video_2s_watched',
  'video_10s_watched',
  'video_15s_watched',
  'video_30s_watched',
  'video_60s_watched'
];

const groupByFields = [
  'account_id', 'campaign_id', 'account_name', 'account_currency', 'adset_id', 'ad_id',
  'date_start', 'date_stop', 'publisher_platform', 'platform_position', 'device_platform',
  'impression_device', 'optimization_goal', 'objective'
];

// Extrai percentuais da curva de play de vídeo e calcula o número absoluto
function extractVideoWatchMetrics(curveValues, totalVideoPlays) {
  const indexMap = {
    video_2s_watched: 2,    // segundo 2
    video_10s_watched: 10,  // segundo 10
    video_15s_watched: 15,  // [15,20)
    video_30s_watched: 18,  // [30,40)
    video_60s_watched: 21   // >60s
  };
  const metrics = {};
  // Garante que totalVideoPlays seja um número válido, caso contrário, usa 0
  const validTotalVideoPlays = typeof totalVideoPlays === 'number' && !isNaN(totalVideoPlays) ? totalVideoPlays : 0;

  if (Array.isArray(curveValues) && validTotalVideoPlays > 0) {
      for (const [key, idx] of Object.entries(indexMap)) {
          const percentage = curveValues[idx];
          const numPercentage = typeof percentage === 'string' ? parseFloat(percentage) : percentage;
          if (idx >= 0 && idx < curveValues.length && typeof numPercentage === 'number' && !isNaN(numPercentage)) {
              metrics[key] = Math.round((numPercentage / 100) * validTotalVideoPlays);
          } else {
              metrics[key] = 0;
          }
      }
  } else {
       for (const [key, idx] of Object.entries(indexMap)) {
           metrics[key] = 0;
       }
  }
  return metrics;
}

function processAdData(data) {
  return data.map(item => {
    const adData = item;
    const actions = adData.actions || [];
    const processedData = {
      account_currency: adData.account_currency,
      account_id: adData.account_id,
      account_name: adData.account_name,
      campaign_id: adData.campaign_id,
      campaign_name: adData.campaign_name,
      adset_id: adData.adset_id,
      adset_name: adData.adset_name,
      ad_id: adData.ad_id,
      ad_name: adData.ad_name,
      objective: adData.objective,
      optimization_goal: adData.optimization_goal,
      date_start: adData.date_start,
      date_stop: adData.date_stop,
      publisher_platform: adData.publisher_platform,
      platform_position: adData.platform_position,
      device_platform: adData.device_platform,
      impression_device: adData.impression_device,

      // Inicializa todos os campos numéricos para 0
      spend: 0,
      impressions: 0,
      clicks: 0,
      reach: 0,
      unique_clicks: 0,
      video_view: 0,
      video_avg_time_watched: 0,
      video_p25_watched: 0,
      video_p50_watched: 0,
      video_p75_watched: 0,
      video_p95_watched: 0,
      video_p100_watched: 0,
      video_play: 0,
      video_2s_watched: 0,
      video_10s_watched: 0,
      video_15s_watched: 0,
      video_30s_watched: 0,
      video_60s_watched: 0,
    };

    // Processa campos numéricos de nível superior (se existirem)
    numericFields.forEach(field => {
        if (adData[field] !== undefined) {
            processedData[field] = Number(adData[field]) || 0;
        }
    });

    // Processa ações
    actions.forEach(action => {
      const key = 'actions_' + action.action_type;
      processedData[key] = Number(action.value) || 0;
      if (action.action_type === 'video_view') {
          processedData.video_view = Number(action.value) || 0;
      }
    });

    // Processa conversões (se existirem)
    if (Array.isArray(adData.conversions)) {
      adData.conversions.forEach(conversion => {
         const key = 'conversions_' + conversion.action_type;
         processedData[key] = Number(conversion.value) || 0;
      });
    }
    // Processa os valores das conversões, se existirem
    if (Array.isArray(adData.conversions_values)) {
      adData.conversions_values.forEach(conv => {
         const key = 'conversions_value_' + conv.action_type;
         processedData[key] = Number(conv.value) || 0;
      });
    }

    // Processa métricas específicas de vídeo a partir de seus respectivos arrays de nível superior
    if (adData.video_avg_time_watched_actions?.length) {
      processedData.video_avg_time_watched = Number(adData.video_avg_time_watched_actions[0].value) || 0;
    }
    if (adData.video_p25_watched_actions?.length) {
      processedData.video_p25_watched = Number(adData.video_p25_watched_actions[0].value) || 0;
    }
    if (adData.video_p50_watched_actions?.length) {
      processedData.video_p50_watched = Number(adData.video_p50_watched_actions[0].value) || 0;
    }
    if (adData.video_p75_watched_actions?.length) {
      processedData.video_p75_watched = Number(adData.video_p75_watched_actions[0].value) || 0;
    }
    if (adData.video_p95_watched_actions?.length) {
      processedData.video_p95_watched = Number(adData.video_p95_watched_actions[0].value) || 0;
    }
    if (adData.video_p100_watched_actions?.length) {
      processedData.video_p100_watched = Number(adData.video_p100_watched_actions[0].value) || 0;
    }
    // Extrai video_play do array de nível superior video_play_actions
    if (adData.video_play_actions?.length) {
      processedData.video_play = Number(adData.video_play_actions[0].value) || 0;
    }

    // Processa métricas da curva de play de vídeo
    if (adData.video_play_curve_actions?.length && Array.isArray(adData.video_play_curve_actions[0]?.value)) {
      const curveMetrics = extractVideoWatchMetrics(adData.video_play_curve_actions[0].value, processedData.video_play);
      Object.assign(processedData, curveMetrics);
    } else {
         const curveMetrics = extractVideoWatchMetrics([], 0);
         Object.assign(processedData, curveMetrics);
    }

    // Garante que todos os campos numéricos sejam Number (redundante, mas seguro)
    numericFields.forEach(field => {
       if (processedData[field] !== undefined) {
         processedData[field] = Number(processedData[field]) || 0;
       }
    });

    return processedData;
  });
}

const outputData = processAdData(inputData);

// Agrupamento e soma
const groupedData = {};
outputData.forEach(item => {
  const key = groupByFields.map(f => item[f]).join('|');
  if (!groupedData[key]) {
    groupedData[key] = { ...item };
  } else {
    numericFields.forEach(field => {
      groupedData[key][field] = (groupedData[key][field] || 0) + (item[field] || 0);
    });
    // Soma os campos de ações dinamicamente adicionados
    Object.keys(item)
      .filter(k => k.startsWith('actions_'))
      .forEach(k => {
        groupedData[key][k] = (groupedData[key][k] || 0) + (item[k] || 0);
      });
    // Soma os campos de conversões dinamicamente adicionados (incluindo os de conversion values)
    Object.keys(item)
      .filter(k => k.startsWith('conversions_'))
      .forEach(k => {
        groupedData[key][k] = (groupedData[key][k] || 0) + (item[k] || 0);
      });
  }
});

const finalResult = Object.values(groupedData);
return finalResult.map(item => ({ json: item }));

